// Validate shared API key
const EXPECTED_KEY = '{{ $env.DDVB_API_KEY }}';

const item = $input.first();
const headers = item.json.headers || {};
const apiKey = headers['x-ddvb-api-key'] || headers['X-DDVB-Api-Key'] || headers['X-DDVB-API-Key'] || '';

if (apiKey !== EXPECTED_KEY) {
  throw new Error('Неверный API ключ. Доступ запрещен.');
}

return [item];

// Normalize incoming web request
const item = $input.first();
const body = item.json.body || item.json;

const jobId = body.jobId || 'job-' + Date.now();
const brief = body.brief || '';
const source = body.source || 'web';
const callbackUrl = body.callbackUrl || '';

return [{
  json: {
    jobId,
    brief,
    source,
    callbackUrl,
    timestamp: new Date().toISOString()
  }
}];

// Parse and validate the incoming request
const item = $input.first();
const data = item.json;

const brief = (data.brief || '').trim();
const jobId = data.jobId || '';
const source = data.source || 'web';
const callbackUrl = data.callbackUrl || '';
const timestamp = data.timestamp || new Date().toISOString();

// Validate brief is not empty
if (!brief) {
  throw new Error('Поле brief обязательно и не может быть пустым.');
}

// Validate Cyrillic presence in brief
const hasCyrillic = /[А-Яа-яЁё]/.test(brief);
if (!hasCyrillic) {
  throw new Error('Бриф должен содержать текст на русском языке (кириллица).');
}

// Extract client name from brief heuristically (first sentence or up to first comma/period)
const clientNameMatch = brief.match(/^[\s\S]*?(?:клиент[а-я]*|компани[а-я]*|бренд[а-я]*)?[:\s]+([^,.\n]{3,60})/i);
const clientName = clientNameMatch ? clientNameMatch[1].trim() : brief.substring(0, 80);

return [{
  json: {
    jobId,
    brief,
    source,
    callbackUrl,
    timestamp,
    clientName,
    hasCyrillic: true
  }
}];

// Merge the 3 fetched prompt texts with parsed request data
const items = $input.all();

// Helper: extract text from GitHub native node (base64) or HTTP fallback
const extractText = (item) => {
  const json = item.json;
  // GitHub native node returns base64-encoded content
  if (json.content && json.encoding === 'base64') {
    return Buffer.from(json.content.replace(/\n/g, ''), 'base64').toString('utf8');
  }
  // Fallback for raw HTTP responses
  if (typeof json.body === 'string') return json.body;
  if (typeof json.data === 'string') return json.data;
  if (typeof json === 'string') return json;
  return JSON.stringify(json);
};

// Items arrive in append order: Perplexity, CaseWriter, Humanizer
const perplexityPrompt = extractText(items[0]);
const caseWriterPrompt = extractText(items[1]);
const humanizerPrompt = extractText(items[2]);

// Pull base request data from Parse Request node
const baseData = $('Parse Request').first().json;

return [{
  json: {
    ...baseData,
    prompts: {
      perplexityResearch: perplexityPrompt,
      caseWriter: caseWriterPrompt,
      humanizer: humanizerPrompt
    },
    promptsLoaded: true,
    promptLoadTimestamp: new Date().toISOString()
  }
}];

