// Extract Claude output and split by ## markers into 4 blocks
const assembledData = $('Assemble Prompts').first().json;

// Get text from chainLlm response
let caseText = '';
try {
  caseText = $input.first().json.text;
} catch (e) {
  throw new Error('Не удалось извлечь текст из ответа Claude: ' + e.message);
}

// Split by ## markers
const blockMap = {};
const rawBlocks = caseText.split(/(?=## )/);

for (const block of rawBlocks) {
  const trimmed = block.trim();
  if (!trimmed) continue;

  // Extract block header and content
  const headerMatch = trimmed.match(/^## (.+?)\n([\s\S]*)$/);
  if (!headerMatch) continue;

  const header = headerMatch[1].trim().toLowerCase();
  const content = headerMatch[2].trim();

  // Map Russian block headers to keys
  if (/заголов|title/i.test(header)) {
    blockMap.title = content;
  } else if (/ситуаци|situation/i.test(header)) {
    blockMap.situation = content;
  } else if (/задач|task/i.test(header)) {
    blockMap.task = content;
  } else if (/решени|solution/i.test(header)) {
    blockMap.solution = content;
  }
}

return [{
  json: {
    ...assembledData,
    caseText,
    blocks: blockMap,
    blocksExtracted: Object.keys(blockMap).length
  }
}];

// Extract humanized text and re-split by ## markers
const prevData = $('Extract Blocks').first().json;

// Get humanized text from chainLlm response
let humanizedText = '';
try {
  humanizedText = $input.first().json.text;
} catch (e) {
  throw new Error('Не удалось извлечь текст из ответа GPT-4o: ' + e.message);
}

// Split by ## markers into 4 blocks
const blockMap = {};
const rawBlocks = humanizedText.split(/(?=## )/);

for (const block of rawBlocks) {
  const trimmed = block.trim();
  if (!trimmed) continue;

  const headerMatch = trimmed.match(/^## (.+?)\n([\s\S]*)$/);
  if (!headerMatch) continue;

  const header = headerMatch[1].trim().toLowerCase();
  const content = headerMatch[2].trim();

  if (/заголов|title/i.test(header)) {
    blockMap.title = content;
  } else if (/ситуаци|situation/i.test(header)) {
    blockMap.situation = content;
  } else if (/задач|task/i.test(header)) {
    blockMap.task = content;
  } else if (/решени|solution/i.test(header)) {
    blockMap.solution = content;
  }
}

return [{
  json: {
    ...prevData,
    humanizedText,
    blocks: blockMap,
    blocksExtracted: Object.keys(blockMap).length
  }
}];

// Validate the humanized portfolio case
const data = $input.first().json;
const blocks = data.blocks || {};
const humanizedText = data.humanizedText || '';

const warnings = [];

// Check all 4 blocks are present
const requiredBlocks = ['title', 'situation', 'task', 'solution'];
const presentBlocks = requiredBlocks.filter(b => blocks[b] && blocks[b].trim().length > 0);
const allBlocksPresent = presentBlocks.length === 4;
if (!allBlocksPresent) {
  const missingBlocks = requiredBlocks.filter(b => !blocks[b] || !blocks[b].trim().length);
  warnings.push('Отсутствуют блоки: ' + missingBlocks.join(', '));
}

// Calculate char count of content blocks
const contentText = [
  blocks.title || '',
  blocks.situation || '',
  blocks.task || '',
  blocks.solution || ''
].join('\n\n');
const charCount = contentText.length;

// Check char count 1500-2000
const charCountOk = charCount >= 1500 && charCount <= 2000;
if (!charCountOk) {
  warnings.push(`Объём контента: ${charCount} символов. Требуется 1500–2000 символов.`);
}

// Check Cyrillic text
const hasCyrillic = /[А-Яа-яЁё]/.test(humanizedText);
if (!hasCyrillic) {
  warnings.push('Текст не содержит кириллицы.');
}

// Check Russian quotes «»
const hasRussianQuotes = /«[^»]+»/.test(humanizedText);
if (!hasRussianQuotes) {
  warnings.push('Отсутствуют русские кавычки «». Замените прямые кавычки на угловые.');
}

const compliancePassed = allBlocksPresent && charCountOk && hasCyrillic;

// Build full content string for output (all blocks with ## markers)
const content = requiredBlocks
  .filter(b => blocks[b])
  .map(b => {
    const headerNames = {
      title: 'Заголовок',
      situation: 'Ситуация',
      task: 'Задача',
      solution: 'Решение'
    };
    return `**${headerNames[b]}**\n${blocks[b]}`;
  })
  .join('\n\n');

return [{
  json: {
    ...data,
    content,
    charCount,
    blocks,
    compliancePassed,
    warnings
  }
}];

// Build callback payload for the web app
const data = $input.first().json;
const parseData = $('Parse Request').first().json;

const startTime = new Date(parseData.timestamp).getTime();
const executionTime = Date.now() - startTime;

const payload = {
  jobId: parseData.jobId,
  status: 'completed',
  workflowType: 'portfolio_case',
  result: {
    content: data.content || '',
    charCount: data.charCount || 0,
    blocks: data.blocks || {},
    compliancePassed: data.compliancePassed || false,
    warnings: data.warnings || []
  },
  executionTime,
  timestamp: new Date().toISOString()
};

return [{
  json: {
    payload,
    callbackUrl: parseData.callbackUrl
  }
}];

// Build error callback payload
let parseData = {};
try {
  parseData = $('Parse Request').first().json;
} catch (e) {
  parseData = { jobId: 'unknown', callbackUrl: '', timestamp: new Date().toISOString() };
}

const data = $input.first().json;
const errorMessage = data.error?.message || data.message || 'Неизвестная ошибка при генерации кейса.';

const startTime = new Date(parseData.timestamp || Date.now()).getTime();
const executionTime = Date.now() - startTime;

const payload = {
  jobId: parseData.jobId || 'unknown',
  status: 'failed',
  workflowType: 'portfolio_case',
  error: errorMessage,
  executionTime,
  timestamp: new Date().toISOString()
};

return [{
  json: {
    payload,
    callbackUrl: parseData.callbackUrl || ''
  }
}];
